import{_ as i,o as l,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung048.jpg",a="/images/uebung047.jpg",c=JSON.parse('{"title":"Übung Lektion 30","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung30.md","filePath":"lektionen/uebung30.md"}'),t={name:"lektionen/uebung30.md"};function d(o,e,m,g,u,h){return l(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-30" tabindex="-1">Übung Lektion 30 <a class="header-anchor" href="#ubung-lektion-30" aria-label="Permalink to &quot;Übung Lektion 30&quot;">​</a></h1><p>A) Wandeln Sie folgende Verbalformen in die in Person, Zahl und Genus verbi entsprechende Optativformen um:</p><ol><li>ह्रियते ह्रियेत</li><li>ध्नन्ति हन्युर्</li><li>स्मरति स्मरेत्</li><li>स्थापयन्ति</li><li>स्तौति स्तुयात्</li><li>सर्ज्यते सर्ज्येत</li><li>सुन्वन्ति सुनुयुर्</li><li>सिञ्चति सिञ्चेत्</li><li>शृणोति शृणुयात्</li><li>शक्नुवन्ति शक्नुयुर्</li><li>वर्तन्ते वर्तेरन्</li><li>वेशयन्ति वेशयेयुर्</li><li>वस्ते वसीत</li><li>उष्यते उष्येत</li><li>वाद्यते वाद्येत</li><li>उच्यते उच्येत</li><li>लम्भ्यते लम्भ्येत</li><li>रक्षयन्ति रक्षयेयुर्</li><li>युध्यते युध्येत</li><li>इज्यते इज्येत</li><li>म्रियते म्रियेत</li><li>मुञ्चन्ति मुञ्चेयुर्</li><li>मन्यन्ते मन्येरन्</li><li>भवति भवेत्</li><li>भजन्ति भजेयुर्</li><li>ब्रवीति ब्रूयात्</li><li>बुध्यते बुध्येत</li><li>पृच्छन्ति पृच्छेयुर्</li><li>पुनाति पुनीयात्</li><li>पाति पायात्</li><li>पीयते पीयेत</li><li>पद्यते पद्येत</li><li>पतति पतेत्</li><li>पाचयन्ति पाचयेयुर्</li><li>नृत्यन्ति नृत्येयुर्</li><li>नीयते नीयेत</li><li>द्विषते द्विषीरन्</li><li>पश्यन्ति पशेयुर्</li><li>दोग्धि दुह्यात्</li><li>दुष्यति दुष्येत्</li><li>देशयन्ति देशयेयुर्</li><li>दहति दहेत्</li><li>तनुते तन्वीत</li><li>जानाति जानीयात्</li><li>जानते जानीरन्</li><li>जयन्ति जयेयुर्</li><li>जायन्ते जायेरन्</li><li>चोर्यते चोर्येत</li><li>चारयति चारयेत्</li><li>गच्छन्ति गच्छेयुर्</li><li>खाद्यते खाद्येत</li><li>क्रीणीते क्रीणीत</li><li>क्रियते क्रियेत</li><li>कोपयति कोपयेत्</li><li>कामयते कामयेत</li><li>इच्छति ईच्छेत्</li><li>आययन्ति आययेयुर्</li><li>आस्यते आस्येत</li><li>आप्नुवते आप्नुवीरन्</li><li>अस्यते अस्येत</li><li>सन्ति स्युर्</li><li>अश्नुते अश्नुवीत</li><li>अर्हति अर्हेत्</li><li>अदन्ति अद्युर्</li><li>अध्यापयन्ति अध्यापयेयुर्</li></ol><p>B) Überrsetzen Sie die folgenden Sätze und lösen Sie die Komposita auf Sanskrit auf:</p><p>जना आर्यसत्यानि जानीयुरिति सुगतेनार्याणां सुखाय जना धर्मं ज्ञाप्यन्ते ॥१॥ आर्याणि सत्यानि । Buddha hat den Menschen zum Heil der Edlen seine Lehre verkündet, damit sie die edlen Wahrheiten erkennen.</p><p>ये नरा देवान्न यजेरन्व्रतानि च न चरेयुरनृतं च वदेयुरधर्मं च कुर्युस्ते स्सुखं नाप्नुयुर्मृत्वा च नरकं पतेयुः ॥२॥ Menschen, der den Göttern nicht opfern, keine Gelübde halten, lügen und Unrecht tun, die werden nicht glücklich und fallen nach ihrem Tod in eine Hölle.</p><p>ज्ञातिरागच्छेतितीष्ट्वार्यपुत्रो ज्ञातिं दासमाययति ॥३॥ आर्यः पुत्रः । आर्याणां पुत्रः । Der edle Sohn will, dass seine Verwandten kommen, und lässt einen Diener die Verwandten holen.</p><p>अन्नलोभाद्दुःखं जायेतेति प्राप्तज्ञानः सुफलानि नाश्नाति ॥४॥ अन्नस्य लोभात् । प्राप्तं ज्ञानं येन स । Zur Einsicht gelangt, dass aus Fressgier Leid entsteht, isst er die guten Früchte nicht,</p><p>क्रयेण च विक्रयेण च वैश्या जीवेयुरिति वैश्यधर्मः । एवं सति वैश्यपुत्राः क्रीणन्ति विक्रीणते च ॥५॥ वैश्यानां पुत्राः । Pflicht der Vaiśyas ist es, von Kauf und Verkauf zu leben. Deshalb kaufen und erkaufen Vaiśyas.</p><p>कृतपापो नरश्चेन्नरके पापात्पूतः स्यात्पुनर्भवं गच्छेत् ॥६॥ कृतं पापं येन सः । पुनर्भवतीति पुनर्भवः । Wenn ein Übeltäter in einer Hölle von seiner Schlechtigkeit gereinigt ist, wird er wiedergeboren.</p><p>ब्राह्मणपुत्रा वेदाध्यायांश्च स्मृत्यध्यायांश्च पुनः पुनरधीयीरन्नित्यार्यधर्मः ॥७॥ ब्राह्मणानां पुत्राः । वेदानामध्यायांश्च स्मृतीनामध्यायांश्च । आर्याणां धर्मः । Pflicht der Edlen ist, dass Brahmanensöhne die Lehrabschnitte der Veden und der Überlieferung immer wieder studieren.</p><p>यो ब्राह्मणः शूद्रां कामयेत स सद्ब्राह्मणो न स्यात् । सद्ब्राह्मणो हि ब्राह्मणीं कामयेत ॥८॥ सन्ब्राह्मणः । Ein Brahmane der eine Śūdra liebt ist kein guter Brahmane, denn ein guter Brahmane liebt eine Brahmanin.</p><p>सत्यं ब्रूयात्प्रियं ब्रूयान्न ब्रूयात्सत्यमप्रियम् ।<br> प्रियं च नानृतं ब्रूयादेष धर्मः सनातनः ॥९॥ ॥मनुस्मृति ४.१३८॥</p><p>Man sage Wahrheiten die angenehm sind,<br> Unangenehme Wahrheiten sage man nicht,<br> Nicht sage man angenehme Unwahrheiten,<br> Dies ist das ewige Gesetz.</p><p><img src="'+s+'" alt=""><br> Abb.: श्रीमोहनभोपेन रावणहस्तो वाद्यते<br> Mohan Bhopa spielt Ravanahatha, Mewar = मेवाड़<br> [Bildquelle: aameducation. -- <a href="http://www.flickr.com/photos/9836216@N06/933464497/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/9836216@N06/933464497/</a>. -- Zugriff am 2008-12-29. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Bestimmen und übersetzen Sie folgende Wortformen:</p><ol><li>भारे Lok. sg. m. auf der Last</li><li>अध्ययनम् Nom./Akk.sg.n Studium</li><li>वस्तुतस् in Wirklichkeit</li><li>वस्त्राणि Nom.Akk.pl.n. Kleider</li><li>प्रतिमया Instr.sg.f. durch ein Bildnis</li><li>आचाराय Dat.sg.m. dem Verhalten</li><li>आचार्यैः Instr.pl.m. durch Lehrer</li><li>अश्वेषु Lok.pl.m. auf Pferden</li><li>ताम् Akk.sg.f. diese</li><li>वृत्त्यै Dat.sg.f. dem Benehmen, der Lebensweise</li><li>चरितस्य Gen.sg.n. des Lebenslaufs</li><li>अर्हता Instr.sg.m. Durch den vollkommen Erlösten</li><li>शक्तीः Akk.pl.f. den Kräften</li><li>कामम् Adv. nach Belieben</li><li>भिक्षवे Dat.sg.m. dem Mönch</li><li>भगवद्गीतायाम् Lok.sg.m. in der Bhagavadgītā</li><li>भगवति lok.sg.m.n. im Ehrwürdigen</li><li>भक्त्याः Abl.Gen.sg.fem. aus Liebe, der Liebe</li><li>स्थानात् Abl.sg.n. aus dem Ort</li><li>स्थित्या Instr.sg.f. durch die Festsetzung</li><li>मात्रायै Dat.sg.f. dem Maß</li><li>प्रभृतौ Lok.sg.f. zu Beginn</li><li>हस्तेन Inst.sg.m. durch die Hand</li><li>आदेः Abl.Gen.sg.m. von Anfang an, des Anfangs</li><li>दिष्टिम् Akk.sg.f. die Anweisung</li><li>रुद्रः Nom.sg.m. Rudra</li><li>मृत्यौ Lok.sg.m. im Tod</li><li>मृतिः Nom.sg.f. der Tod</li><li>द्विजातये Dat.sg.m.f. dem Zweimalgeborenen, der Zweimalgeborenen</li><li>जातिभिः Insr.pl.f. durch die Geburten</li><li>व्वाघ्रान् Akk.pl.m. den Tigern</li><li>पूजाः Nom.Akk.pl.f. die Verehrungen</li><li>शत्रोः Abl.Gen.sg.m. vom Feind, des Feindes</li><li>उक्तिभ्यः Dat.Abl.pl.f. den Aussprüchen, von den Aussprüchen</li><li>महान्ति Nom.Akk.pl.n. die großen</li><li>महति Lok.sg.m.n. im großen</li><li>सा Nom.sg.f. sie, diese</li><li>तस्यै Dat.sg.f. ihr</li><li>तस्मिन् Lok.sg.m. darinnen</li><li>सते Dat.sg.m.n. dem seienden/wahren/guten</li></ol><p><img src="'+a+'" alt=""><br> Abb.: भक्त्याः<br> Hare Krishna devotees perform a parade in Florida, USA in 2008<br> [Bildquelle: Tim Ross / Wikipedia. Public domain]</p><p>Zu den Lösungen der <a href="./uebung31">Übungen Lektion 31 - 35</a></p>',20)])])}const b=i(t,[["render",d]]);export{c as __pageData,b as default};
